def decrypt_data(data, layers=1):
    current = data
    
    for layer in range(layers-1, -1, -1):
        if layer > 0:
            current = base64.b64decode(current).decode()
        
        # فك التشويش
        parts = current.split(".")
        decoded = ''.join(chr(int(p) - 100 - layer) for p in parts)
        
        # فك rot13
        current = decoded.translate(
            str.maketrans(
                'NOPQRSTUVWXYZABCDEFGHIJKLMnopqrstuvwxyzabcdefghijklm5678901234+/',
                'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
            )
        )
    
    # فك الضغط
    decompressed = zlib.decompress(base64.b64decode(current))
    return decompressed.decode()

try:
    result = decrypt_data(encrypted)
    exec(result)
except Exception as e:
    print("❌ خطأ في فك التشفير:", e)
